import mongoose, { Schema, Document } from 'mongoose';

interface UserDocument extends Document {
  username: string;
  passwordHash: string;
  email: string;
  createdAt: Date;
}

const UserSchema: Schema = new Schema<UserDocument>({
  username: { type: String, required: true, unique: true },
  passwordHash: { type: String, required: true },
  email: { type: String, required: true, unique: true },
  createdAt: { type: Date, default: Date.now }
});

export default mongoose.model<UserDocument>('User', UserSchema);

import { UserDocument } from './user.model';
import User from './user.model';

class UserRepository {
  async createUser(userData: Partial<UserDocument>): Promise<UserDocument> {
    const user = new User(userData);
    return user.save();
  }

  async findUserById(userId: string): Promise<UserDocument | null> {
    return User.findById(userId).exec();
  }

  async findUserByUsername(username: string): Promise<UserDocument | null> {
    return User.findOne({ username }).exec();
  }

  async findUserByEmail(email: string): Promise<UserDocument | null> {
    return User.findOne({ email }).exec();
  }
}

export default new UserRepository();

interface UserDTO {
  id: string;
  username: string;
  email: string;
  createdAt: Date;
}

interface CreateUserDTO {
  username: string;
  password: string;
  email: string;
}

interface LoginDTO {
  username: string;
  password: string;
}

export { UserDTO, CreateUserDTO, LoginDTO };

import { z } from 'zod';

const createUserSchema = z.object({
  username: z.string().min(5),
  password: z.string().min(8),
  email: z.string().email()
});

const loginUserSchema = z.object({
  username: z.string(),
  password: z.string().min(8)
});

export { createUserSchema, loginUserSchema };

import { Request, Response } from 'express';
import { createUserSchema, loginUserSchema } from './user.validator';
import UserService from './user.service';

class UserController {
  async register(req: Request, res: Response): Promise<void> {
    const validation = createUserSchema.safeParse(req.body);
    if (!validation.success) {
      res.status(400).json({ success: false, message: validation.error.message });
      return;
    }
    const userDTO = validation.data;
    const user = await UserService.registerUser(userDTO);
    res.status(201).json({ success: true, data: user });
  }

  async login(req: Request, res: Response): Promise<void> {
    const validation = loginUserSchema.safeParse(req.body);
    if (!validation.success) {
      res.status(400).json({ success: false, message: validation.error.message });
      return;
    }
    const loginDTO = validation.data;
    const token = await UserService.loginUser(loginDTO);
    res.status(200).json({ success: true, data: { token } });
  }
}

export default new UserController();

import bcrypt from 'bcrypt';
import jwt from 'jsonwebtoken';
import UserRepository from './user.repository';
import { CreateUserDTO, LoginDTO, UserDTO } from './user.dto';
import { AppError } from '../../utils/app-error';

class UserService {
  private static SALT_ROUNDS = 10;

  async registerUser(userDTO: CreateUserDTO): Promise<UserDTO> {
    const hashedPassword = await bcrypt.hash(userDTO.password, UserService.SALT_ROUNDS);
    const newUser = await UserRepository.createUser({ ...userDTO, passwordHash: hashedPassword });
    return this.mapToUserDTO(newUser);
  }

  async loginUser({ username, password }: LoginDTO): Promise<string> {
    const user = await UserRepository.findUserByUsername(username);
    if (!user || !(await bcrypt.compare(password, user.passwordHash))) {
      throw new AppError('InvalidCredentials', 'The username or password you provided is incorrect.', 401);
    }
    return jwt.sign({ id: user.id, username: user.username }, process.env.JWT_SECRET!, { expiresIn: '1h' });
  }

  private mapToUserDTO(user: any): UserDTO {
    return {
      id: user.id,
      username: user.username,
      email: user.email,
      createdAt: user.createdAt
    };
  }
}

export default new UserService();
